noncompliant:
class Base {
    virtual void f1();
};

class C final : Base {
    virtual void f1(); // Noncompliant: virtual is confusing in final class
    virtual void f2(); // Noncompliant: new virtual in final class
};

class Calculator final {
    virtual int calculate(int a, int b); // Noncompliant: virtual makes no sense
};

compliant:
class Base {
    virtual void f1();
};

class C final : Base {
    void f1() override; // Compliant: override instead of virtual
    void f2(); // Compliant: non-virtual function
};

class Calculator final {
    int calculate(int a, int b); // Compliant: no virtual needed
};
